import React, { useState, useEffect, useContext } from 'react';
import { useTranslation } from 'react-i18next';
import api from '../utils/api';
import { AuthContext } from '../context/AuthContext';
import { Link } from 'react-router-dom';
import JobLocationMap from '../components/JobLocationMap';
import MapComponent from '../components/MapComponent';
import './WorkerDashboardNew.css';
const WorkerDashboard = () => {
  const { user } = useContext(AuthContext);
  const { t } = useTranslation();
  const [activePage, setActivePage] = useState('dashboard');
  const [activeTab, setActiveTab] = useState('available');
  const [jobs, setJobs] = useState([]);
  const [myJobs, setMyJobs] = useState([]);
  const [earnings, setEarnings] = useState(null);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [appliedJobs, setAppliedJobs] = useState(new Set());
  const [applyingJobId, setApplyingJobId] = useState(null);
  const [profileData, setProfileData] = useState(user || {});
  const [isEditing, setIsEditing] = useState(false);
  const [monthlyEarnings, setMonthlyEarnings] = useState({});
  const [workAnalytics, setWorkAnalytics] = useState({
    dailyHours: [],
    dailyIncome: [],
    monthlyIncome: [],
    workCapacity: []
  });
  const [analyticsFilter, setAnalyticsFilter] = useState('7days');
  const [notifications, setNotifications] = useState([]);
  const [mapPosition, setMapPosition] = useState({
    lat: 20.5937,
    lng: 78.9629
  });
  const [isMapVisible, setIsMapVisible] = useState(false);

  const categories = [
    { id: 'all', label: 'All Jobs', icon: '📋' },
    { id: 'painting', label: 'Painting', icon: '🎨' },
    { id: 'electrical', label: 'Electrical', icon: '⚡' },
    { id: 'masonry', label: 'Masonry', icon: '🧱' },
    { id: 'plumbing', label: 'Plumbing', icon: '🚰' },
    { id: 'carpentry', label: 'Carpentry', icon: '🪚' },
    { id: 'welding', label: 'Welding', icon: '🔥' },
    { id: 'construction', label: 'Construction', icon: '🏗️' },
    { id: 'cleaning', label: 'Cleaning', icon: '🧹' },
    { id: 'gardening', label: 'Gardening', icon: '🌱' },
    { id: 'loading', label: 'Loading', icon: '📦' },
    { id: 'fabrication', label: 'Fabrication', icon: '🛠️' },
    { id: 'tiling', label: 'Tiling', icon: '📐' }
  ];

  const handleApplyJob = async (jobId) => {
    try {
      setApplyingJobId(jobId);
      const response = await api.post(`/jobs/${jobId}/apply`, {
        proposedRate: undefined,
        message: 'Interested in this job'
      });

      if (response.data.success) {
        setAppliedJobs(new Set([...appliedJobs, jobId]));
        alert('✅ Job application submitted successfully!');
      }
    } catch (error) {
      alert('❌ ' + (error.response?.data?.message || 'Failed to apply for job'));
    } finally {
      setApplyingJobId(null);
    }
  };

  const handleAcceptJob = async (jobId) => {
    if (!window.confirm('Are you sure you want to accept this job?')) return;

    try {
      const response = await api.post(`/jobs/${jobId}/accept`);

      if (response.data.success) {
        alert('✅ Job accepted successfully! A chat conversation has been created with the employer.');
        // Refresh dashboard data
        fetchDashboardData();
      }
    } catch (error) {
      alert('❌ ' + (error.response?.data?.message || 'Failed to accept job'));
    }
  };

  const handleRejectJob = async (jobId) => {
    if (!window.confirm('Are you sure you want to reject this job?')) return;
    try {
      const response = await api.post(`/jobs/${jobId}/reject`);

      if (response.data.success) {
        alert('❌ Job rejected successfully. Notification sent to employer.');
        // Refresh dashboard data
        fetchDashboardData();
      }
    } catch (error) {
      alert('❌ ' + (error.response?.data?.message || 'Failed to reject job'));
    }
  };

  const handleSaveProfile = async () => {
    try {
      // Make sure location exists in profileData
      const updatedProfileData = {
        ...profileData,
        location: {
          ...profileData.location,
          coordinates: profileData.location?.coordinates || null
        }
      };

      const response = await api.put('/workers/profile', updatedProfileData);
      if (response.data.success) {
        alert('✅ Profile updated successfully!');
        setIsEditing(false);
      }
    } catch (error) {
      alert('❌ Error updating profile: ' + (error.response?.data?.message || 'Unknown error'));
    }
  };

  const handleAvailabilityToggle = async () => {
    const currentStatus = profileData.availability?.status || 'available';
    const newStatus = currentStatus === 'available' ? 'busy' : 'available';
    try {
      const response = await api.put('/workers/profile', {
        ...profileData,
        availability: {
          ...profileData.availability,
          status: newStatus
        }
      });
      if (response.data.success) {
        setProfileData(prev => ({
          ...prev,
          availability: {
            ...prev.availability,
            status: newStatus
          }
        }));
      }
    } catch (error) {
      console.error('Error updating availability:', error);
      alert('Failed to update availability status');
    }
  };

  const handleProfileChange = (field, value) => {
    // Handle nested properties (e.g., 'location.city')
    if (field.includes('.')) {
      const [parent, child] = field.split('.');
      setProfileData({
        ...profileData,
        [parent]: {
          ...(profileData[parent] || {}),
          [child]: value
        }
      });
    } else {
      setProfileData({
        ...profileData,
        [field]: value
      });
    }
  };

  const handleMapLocationChange = (position) => {
    setMapPosition(position);
    // Update profile data with coordinates
    setProfileData(prev => ({
      ...prev,
      location: {
        ...prev.location,
        coordinates: {
          latitude: position.lat,
          longitude: position.lng
        }
      }
    }));
  };

  const fetchDashboardData = async () => {
    try {
      setLoading(true);
      const query = filter !== 'all' ? `?category=${filter}` : '';
      const [jobsRes, myJobsRes, earningsRes] = await Promise.all([
        api.get(`/workers/available-jobs${query}`),
        api.get('/workers/my-jobs?status=assigned'),
        api.get('/workers/earnings')
      ]);
      setJobs(jobsRes.data.jobs);
      setMyJobs(myJobsRes.data.jobs);
      setEarnings(earningsRes.data.earnings);
      setMonthlyEarnings(earningsRes.data.earnings?.monthlyBreakdown || {});

      // Fetch work analytics
      fetchWorkAnalytics();
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchDashboardData();
    fetchNotifications();

    // Update map position when profile data changes
    if (profileData.location?.coordinates?.latitude && profileData.location?.coordinates?.longitude) {
      setMapPosition({
        lat: profileData.location.coordinates.latitude,
        lng: profileData.location.coordinates.longitude
      });
    }
  }, [profileData, filter, activePage, analyticsFilter]);

  const fetchWorkAnalytics = async () => {
    try {
      const response = await api.get(`/workers/analytics?period=${analyticsFilter}`);
      if (response.data.success) {
        setWorkAnalytics(response.data.analytics);
      }
    } catch (error) {
      console.error('Error fetching analytics:', error);
      // Fallback to mock data if API fails
      const mockAnalytics = generateMockAnalytics(analyticsFilter);
      setWorkAnalytics(mockAnalytics);
    }
  };

  const fetchNotifications = async () => {
    try {
      // Get conversations that have job offers for this worker
      const response = await api.get('/chat/conversations');
      if (response.data.success) {
        const jobOfferConversations = response.data.conversations.filter(
          conv => conv.jobOffer && conv.jobOffer.status === 'pending'
        );

        // Transform to notification format
        const newNotifications = jobOfferConversations.map(conv => {
          const otherParticipant = conv.participants.find(p => p._id !== user.id);
          return {
            id: conv._id,
            type: 'job_offer',
            title: 'Job Offer Received',
            message: `${otherParticipant?.name} offered you a job`,
            timestamp: conv.jobOffer.offeredAt,
            status: 'unread',
            conversationId: conv._id,
            conversation: conv // Store the full conversation for later use
          };
        });

        setNotifications(newNotifications);
      }
    } catch (error) {
      console.error('Error fetching notifications:', error);
    }
  };

  const generateMockAnalytics = (filter) => {
    const days = filter === '7days' ? 7 : filter === '30days' ? 30 : 90;
    const dailyHours = [];
    const dailyIncome = [];
    const workCapacity = [];

    for (let i = days - 1; i >= 0; i--) {
      const date = new Date();
      date.setDate(date.getDate() - i);

      // Generate realistic mock data
      const hours = Math.floor(Math.random() * 10) + 4; // 4-14 hours
      const income = hours * (Math.floor(Math.random() * 300) + 200); // ₹200-500 per hour
      const capacity = Math.min(100, Math.floor(hours / 12 * 100)); // Percentage capacity

      dailyHours.push({
        date: date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
        hours: hours
      });

      dailyIncome.push({
        date: date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
        income: income
      });

      workCapacity.push({
        date: date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
        capacity: capacity
      });
    }

    // Calculate monthly income
    const monthlyIncome = [
      { month: 'Jan 2024', income: 45000 },
      { month: 'Feb 2024', income: 52000 },
      { month: 'Mar 2024', income: 48000 },
      { month: 'Apr 2024', income: 55000 },
      { month: 'May 2024', income: 49000 },
      { month: 'Jun 2024', income: 58000 }
    ];

    return {
      dailyHours,
      dailyIncome,
      monthlyIncome,
      workCapacity
    };
  };

  const renderDashboardPage = () => {
    return (
      <div className="tab-content-area dashboard-section">
        <div className="welcome-banner">
          <div className="welcome-text">
            <h1>{t('worker.welcome', { name: user?.name })}</h1>
            <p>{profileData.availability?.status === 'available' ? t('worker.acceptingJobs') : t('worker.currentlyBusy')}</p>
          </div>
          <div className="welcome-action">
            <button className="post-job-btn" onClick={() => setActivePage('settings')}>
              ⚙️ {t('worker.tabs.settings')}
            </button>
          </div>
        </div>

        <div className="stats-grid">
          <div className="stat-card">
            <div className="stat-icon">💰</div>
            <div className="stat-content">
              <h4>{t('worker.stats.totalEarnings')}</h4>
              <p className="stat-value">₹{earnings?.total || 0}</p>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon">🎯</div>
            <div className="stat-content">
              <h4>{t('worker.stats.jobsCompleted')}</h4>
              <p className="stat-value">{earnings?.completedJobs || 0}</p>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon">⏳</div>
            <div className="stat-content">
              <h4>{t('worker.stats.pendingPayments')}</h4>
              <p className="stat-value">₹{earnings?.pendingPayments || 0}</p>
            </div>
          </div>
        </div>

        <div className="tabs-section" style={{ marginTop: '2rem' }}>
          <div className="tab-buttons">
            <button
              className={`tab-btn ${activeTab === 'active' ? 'active' : ''}`}
              onClick={() => setActiveTab('active')}
            >
              🏢 {t('worker.tabs.active')} ({myJobs.length})
            </button>
            <button
              className={`tab-btn ${activeTab === 'available' ? 'active' : ''}`}
              onClick={() => setActiveTab('available')}
            >
              🔍 {t('worker.tabs.available')} ({jobs.length})
            </button>
          </div>
        </div>

        {activeTab === 'active' ? (
          <div className="section-card" style={{ marginTop: '1.5rem' }}>
            <div className="card-header">
              <h3>{t('worker.tabs.active')}</h3>
            </div>
            {myJobs.length > 0 ? (
              <div className="jobs-list">
                {myJobs.map(job => (
                  <div key={job._id} className="job-card active-job">
                    <div className="job-badge">ACTIVE</div>
                    <div className="job-info">
                      <h3>{job.title}</h3>
                      <p className="job-category">{job.category}</p>
                      <p className="job-employer">👤 {job.employer?.name}</p>
                      <p className="job-location">📍 {job.location?.city}, {job.location?.district}</p>
                      {job.location?.coordinates?.latitude && job.location?.coordinates?.longitude && (
                        <div className="job-map-container">
                          <JobLocationMap job={job} height="150px" />
                        </div>
                      )}
                    </div>
                    <div className="job-action">
                      <p className="job-price">₹{job.wageCalculation?.totalEstimated}</p>
                      <Link to={`/job/${job._id}`} className="view-btn">{t('common.viewDetails')}</Link>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="empty-state">
                <span className="empty-icon">🏢</span>
                <p>No active jobs right now</p>
              </div>
            )}
          </div>
        ) : (
          <div className="available-jobs-container">
            <div className="section-card quick-hire-categories" style={{ marginBottom: '2rem' }}>
              <h3>{t('worker.available.filter')}</h3>
              <div className="categories-grid">
                {categories.map(cat => (
                  <div
                    key={cat.id}
                    className={`category-item ${filter === cat.id ? 'active' : ''}`}
                    onClick={() => setFilter(cat.id)}
                  >
                    <span className="category-icon">{cat.icon}</span>
                    <span className="category-label">{cat.label}</span>
                  </div>
                ))}
              </div>
            </div>

            <div className="section-card">
              <div className="card-header">
                <h3>{t('worker.tabs.available')} ({jobs.length})</h3>
              </div>

              {jobs.length > 0 ? (
                <div className="jobs-list">
                  {jobs.map(job => (
                    <div key={job._id} className="job-card available-job">
                      <div className="job-header">
                        <h3>{job.title}</h3>
                        <span className={`urgency-badge ${job.urgency}`}>🔴 {job.urgency.toUpperCase()}</span>
                      </div>
                      <p className="job-category">Category: {job.category}</p>
                      <p className="job-employer">👤 Posted by: {job.employer?.name}</p>
                      <p className="job-location">📍 {job.location?.city}</p>
                      <div className="job-details">
                        <div className="detail-item">
                          <span className="label">⏱️ Duration:</span>
                          <span className="value">{job.duration?.estimated} {job.duration?.unit}</span>
                        </div>
                        <div className="detail-item">
                          <span className="label">💰 Estimated Pay:</span>
                          <span className="value price">₹{job.wageCalculation?.totalEstimated}</span>
                        </div>
                      </div>
                      <div className="job-action-buttons">
                        {job.status === 'assigned' && job.assignedWorkers && job.assignedWorkers.some(aw => aw.worker.toString() === user.id) ? (
                          <div className="job-actions">
                            <button
                              className="apply-btn accept-job-btn"
                              onClick={() => handleAcceptJob(job._id)}
                            >
                              ✅ Accept
                            </button>
                            <button
                              className="apply-btn reject-job-btn"
                              onClick={() => handleRejectJob(job._id)}
                            >
                              ❌ Reject
                            </button>
                          </div>
                        ) : (
                          <button
                            className="apply-btn"
                            onClick={() => handleApplyJob(job._id)}
                            disabled={appliedJobs.has(job._id) || applyingJobId === job._id}
                          >
                            {appliedJobs.has(job._id) ? '✅ Applied' : (applyingJobId === job._id ? '⏳ Applying...' : '📝 Apply Now')}
                          </button>
                        )}
                        <Link to={`/job/${job._id}`} className="view-btn">{t('common.viewDetails')}</Link>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="empty-state">
                  <span className="empty-icon">🔍</span>
                  <p>No jobs found matching your skills right now.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    );
  };

  const renderHistoryPage = () => {
    // Calculate averages
    const avgDailyHours = workAnalytics.summary?.averageDailyHours ||
      (workAnalytics.dailyHours.length > 0
        ? (workAnalytics.dailyHours.reduce((sum, item) => sum + item.hours, 0) / workAnalytics.dailyHours.length).toFixed(1)
        : 0);

    const avgDailyIncome = workAnalytics.summary?.averageDailyIncome ||
      (workAnalytics.dailyIncome.length > 0
        ? (workAnalytics.dailyIncome.reduce((sum, item) => sum + item.income, 0) / workAnalytics.dailyIncome.length).toFixed(0)
        : 0);

    const totalMonthlyIncome = workAnalytics.monthlyIncome.length > 0
      ? workAnalytics.monthlyIncome[workAnalytics.monthlyIncome.length - 1]?.income || 0
      : 0;

    const avgCapacity = workAnalytics.summary?.averageCapacity ||
      (workAnalytics.workCapacity.length > 0
        ? (workAnalytics.workCapacity.reduce((sum, item) => sum + item.capacity, 0) / workAnalytics.workCapacity.length).toFixed(0)
        : 0);

    return (
      <div className="tab-content-area history-section">
        <div className="section-header" style={{ marginBottom: '2rem' }}>
          <h1>📊 {t('worker.analytics.title')}</h1>
          <div className="header-actions">
            <select
              value={analyticsFilter}
              onChange={(e) => {
                setAnalyticsFilter(e.target.value);
                fetchWorkAnalytics();
              }}
              className="filter-select"
            >
              <option value="7days">{t('worker.analytics.last7')}</option>
              <option value="30days">{t('worker.analytics.last30')}</option>
              <option value="90days">{t('worker.analytics.last90')}</option>
            </select>
          </div>
        </div>

        <div className="stats-grid">
          <div className="stat-card">
            <div className="stat-icon">⏱️</div>
            <div className="stat-content">
              <h4>{t('worker.analytics.avgHours')}</h4>
              <p className="stat-value">{avgDailyHours} hrs</p>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon">💰</div>
            <div className="stat-content">
              <h4>{t('worker.analytics.dailyIncome')}</h4>
              <p className="stat-value">₹{avgDailyIncome}</p>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon">📅</div>
            <div className="stat-content">
              <h4>{t('worker.analytics.monthlyIncome')}</h4>
              <p className="stat-value">₹{totalMonthlyIncome.toLocaleString()}</p>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon">💪</div>
            <div className="stat-content">
              <h4>{t('worker.analytics.capacity')}</h4>
              <p className="stat-value">{avgCapacity}%</p>
            </div>
          </div>
        </div>

        <div className="charts-grid" style={{ marginTop: '2rem', display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(400px, 1fr))', gap: '2rem' }}>
          <div className="section-card chart-container">
            <div className="card-header">
              <h3>📈 {t('worker.analytics.dailyHoursTitle')}</h3>
            </div>
            <div className="bar-chart" style={{ padding: '1rem' }}>
              {workAnalytics.dailyHours.map((item, index) => (
                <div key={index} className="chart-bar">
                  <div
                    className="bar-fill"
                    style={{ height: `${(item.hours / 14) * 100}%` }}
                  >
                    <span className="bar-value">{item.hours}h</span>
                  </div>
                  <span className="bar-label">{item.date}</span>
                </div>
              ))}
            </div>
          </div>

          <div className="section-card chart-container">
            <div className="card-header">
              <h3>💰 {t('worker.analytics.dailyIncomeTitle')}</h3>
            </div>
            <div className="line-chart" style={{ padding: '1rem', position: 'relative', height: '200px' }}>
              <div className="chart-line">
                {workAnalytics.dailyIncome.map((item, index) => {
                  const maxIncome = Math.max(...workAnalytics.dailyIncome.map(d => d.income));
                  const heightPercent = maxIncome > 0 ? (item.income / maxIncome) * 80 : 0;
                  return (
                    <div
                      key={index}
                      className="line-point"
                      style={{
                        left: `${(index / (workAnalytics.dailyIncome.length - 1)) * 100}%`,
                        bottom: `${heightPercent}%`
                      }}
                    >
                      <div className="point-tooltip">₹{item.income}</div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>

        <div className="section-card" style={{ marginTop: '2rem' }}>
          <div className="card-header">
            <h3>📅 {t('worker.analytics.monthlyBreakdown')}</h3>
          </div>
          <div className="table-responsive">
            {Object.keys(monthlyEarnings).length > 0 ? (
              <table className="data-table">
                <thead>
                  <tr>
                    <th>{t('worker.analytics.month')}</th>
                    <th>{t('worker.analytics.earnings')}</th>
                  </tr>
                </thead>
                <tbody>
                  {Object.entries(monthlyEarnings).map(([month, amount]) => (
                    <tr key={month}>
                      <td>{month}</td>
                      <td className="amount">₹{amount}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <div className="empty-state">
                <p>{t('common.noData')}</p>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  };

  const renderSettingsPage = () => {
    return (
      <div className="tab-content-area settings-section">
        <div className="section-header" style={{ marginBottom: '2rem' }}>
          <h1>⚙️ {t('worker.settings.title')}</h1>
        </div>

        <div className="settings-container">
          <div className="section-card">
            <div className="card-header">
              <h3>👤 {t('worker.settings.personalInfo')}</h3>
            </div>
            <div className="card-content">
              {isEditing ? (
                <div className="edit-form">
                  <div className="form-group">
                    <label>👤 {t('worker.settings.fullName')}</label>
                    <input
                      type="text"
                      className="form-input"
                      value={profileData.name || ''}
                      onChange={(e) => handleProfileChange('name', e.target.value)}
                    />
                  </div>
                  <div className="form-group">
                    <label>📞 {t('worker.settings.phone')}</label>
                    <input
                      type="text"
                      className="form-input"
                      value={profileData.phone || ''}
                      onChange={(e) => handleProfileChange('phone', e.target.value)}
                    />
                  </div>
                  <div className="form-group">
                    <label>📝 {t('worker.settings.bio')}</label>
                    <textarea
                      className="form-input"
                      value={profileData.bio || ''}
                      onChange={(e) => handleProfileChange('bio', e.target.value)}
                      rows="4"
                      placeholder={t('worker.settings.bioPlaceholder')}
                    />
                  </div>
                  <div className="form-actions">
                    <button className="save-btn" onClick={handleSaveProfile}>✅ {t('common.save')}</button>
                    <button className="cancel-btn" onClick={() => setIsEditing(false)}>✖️ {t('common.cancel')}</button>
                  </div>
                </div>
              ) : (
                <div className="profile-view">
                  <div className="info-row">
                    <span className="label">👤 {t('worker.settings.fullName')}:</span>
                    <span className="value">{profileData.name}</span>
                  </div>
                  <div className="info-row">
                    <span className="label">📞 {t('worker.settings.phone')}:</span>
                    <span className="value">{profileData.phone}</span>
                  </div>
                  <div className="info-row">
                    <span className="label">📧 {t('employer.profile.email')}:</span>
                    <span className="value">{profileData.email}</span>
                  </div>
                  <div className="info-row">
                    <span className="label">📝 {t('worker.settings.bio')}:</span>
                    <span className="value">{profileData.bio || t('worker.settings.notSet')}</span>
                  </div>
                  <button className="edit-btn" onClick={() => setIsEditing(true)}>✏️ {t('worker.settings.editProfile')}</button>
                </div>
              )}
            </div>
          </div>

          <div className="section-card" style={{ marginTop: '2rem' }}>
            <div className="card-header">
              <h3>📍 {t('worker.settings.location')}</h3>
            </div>
            <div className="card-content">
              {isEditing ? (
                <div className="edit-form">
                  <div className="form-group">
                    <label>📍 {t('worker.settings.address')}</label>
                    <input
                      type="text"
                      className="form-input"
                      value={profileData.location?.address || ''}
                      onChange={(e) => handleProfileChange('location.address', e.target.value)}
                    />
                  </div>
                  <div className="grid-2-col" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                    <div className="form-group">
                      <label>🏙️ {t('worker.settings.city')}</label>
                      <input
                        type="text"
                        className="form-input"
                        value={profileData.location?.city || ''}
                        onChange={(e) => handleProfileChange('location.city', e.target.value)}
                      />
                    </div>
                    <div className="form-group">
                      <label>📌 {t('worker.settings.district')}</label>
                      <input
                        type="text"
                        className="form-input"
                        value={profileData.location?.district || ''}
                        onChange={(e) => handleProfileChange('location.district', e.target.value)}
                      />
                    </div>
                  </div>
                  <div className="location-actions" style={{ marginTop: '1rem' }}>
                    <button
                      type="button"
                      onClick={() => setIsMapVisible(!isMapVisible)}
                      className="view-btn"
                    >
                      {isMapVisible ? t('worker.settings.hideMap') : t('worker.settings.showMap')}
                    </button>
                  </div>
                </div>
              ) : (
                <div className="location-view">
                  <div className="info-row">
                    <span className="label">📍 {t('worker.settings.address')}:</span>
                    <span className="value">{profileData.location?.address}, {profileData.location?.city}</span>
                  </div>
                  <div className="info-row">
                    <span className="label">📌 {t('worker.settings.district')}:</span>
                    <span className="value">{profileData.location?.district}</span>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    );
  };


  if (loading) return <div className="loading">Loading dashboard...</div>;

  return (
    <div className="dashboard-layout">
      {/* Sidebar Navigation */}
      <aside className="dashboard-sidebar">
        <div className="sidebar-header">
          <div className="employer-avatar">
            {user?.name?.charAt(0) || 'W'}
          </div>
          <h3>{user?.name}</h3>
          <p>{t('role.worker', { defaultValue: 'Worker' })}</p>
        </div>

        <nav className="sidebar-nav">
          <button
            className={`nav-item ${activePage === 'dashboard' ? 'active' : ''}`}
            onClick={() => setActivePage('dashboard')}
          >
            <span className="nav-icon">📊</span> {t('navbar.dashboard')}
          </button>
          <button
            className={`nav-item ${activePage === 'active' ? 'active' : ''}`}
            onClick={() => setActivePage('active')}
          >
            <span className="nav-icon">🏢</span> {t('worker.tabs.active')} ({myJobs.length})
          </button>
          <button
            className={`nav-item ${activePage === 'history' ? 'active' : ''}`}
            onClick={() => setActivePage('history')}
          >
            <span className="nav-icon">📋</span> {t('worker.tabs.history')}
          </button>
          <button
            className={`nav-item ${activePage === 'settings' ? 'active' : ''}`}
            onClick={() => setActivePage('settings')}
          >
            <span className="nav-icon">⚙️</span> {t('worker.tabs.settings')}
          </button>
          <button
            className="nav-item logout-btn"
            style={{ marginTop: 'auto' }}
            onClick={() => {
              if (window.confirm('Are you sure you want to logout?')) {
                window.location.href = '/login';
              }
            }}
          >
            <span className="nav-icon">🚪</span> {t('navbar.logout')}
          </button>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="dashboard-main">
        {activePage === 'dashboard' && renderDashboardPage()}
        {activePage === 'active' && (
          <div className="tab-content-area active-jobs-section">
            <div className="section-header" style={{ marginBottom: '2rem' }}>
              <h1>🏢 {t('worker.tabs.active')}</h1>
            </div>

            <div className="section-card">
              <div className="card-header">
                <h3>{t('worker.tabs.active')} ({myJobs.length})</h3>
              </div>
              {myJobs.length > 0 ? (
                <div className="jobs-list">
                  {myJobs.map(job => (
                    <div key={job._id} className="job-card active-job">
                      <div className="job-badge">ACTIVE</div>
                      <div className="job-info">
                        <h3>{job.title}</h3>
                        <p className="job-category">{job.category}</p>
                        <p className="job-employer">👤 {job.employer?.name}</p>
                        <p className="job-location">📍 {job.location?.city}</p>
                        {job.location?.coordinates?.latitude && job.location?.coordinates?.longitude && (
                          <div className="job-map-container">
                            <JobLocationMap job={job} height="150px" />
                          </div>
                        )}
                      </div>
                      <div className="job-action">
                        <p className="job-price">₹{job.wageCalculation?.totalEstimated}</p>
                        <Link to={`/job/${job._id}`} className="view-btn">{t('common.viewDetails')}</Link>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="empty-state">
                  <span className="empty-icon">🏢</span>
                  <p>{t('common.noData')}</p>
                </div>
              )}
            </div>
          </div>
        )}
        {activePage === 'history' && renderHistoryPage()}
        {activePage === 'settings' && renderSettingsPage()}
      </main>
    </div>
  );
};

export default WorkerDashboard;
